function so_n($v,$d=2){return round((float)$v,$d);}function so_ready(){return chb_table_exists('sales_orders')&&chb_table_exists('sales_order_items');}
$ready=false;try{chb_db();$ready=so_ready();}catch(Throwable $e){$errors[]=$e->getMessage();}
if($ready&&$_SERVER['REQUEST_METHOD']==='POST'){
 try{chb_verify_csrf();$act=$_POST['action']??'save';
  if($act==='save'){
   if(!chb_can('sales_orders.add'))throw new RuntimeException('Permission denied.');
   $cust=trim($_POST['customer_name']??''); if($cust==='')throw new RuntimeException('Customer required.');
   $items=[];$sub=0;foreach(($_POST['product_name']??[]) as $i=>$pn){$pn=trim((string)$pn);if($pn==='')continue;$bag=so_n($_POST['bag_qty'][$i]??0,3);$kg=so_n($_POST['kg_per_bag'][$i]??25,3);$rate=so_n($_POST['rate'][$i]??0);if($bag<=0||$kg<=0)continue;$tk=so_n($bag*$kg,3);$lt=so_n($tk*$rate);$sub+=$lt;$items[]=[(int)($_POST['product_id'][$i]??0),$pn,trim($_POST['grade'][$i]??''),$bag,$kg,$tk,$rate,$lt,$i+1];}
   if(!$items)throw new RuntimeException('At least one product required.');
   $discount=so_n($_POST['discount_amount']??0);$transport=so_n($_POST['transport_amount']??0);$vat=so_n($_POST['vat_amount']??0);$grand=so_n($sub-$discount+$transport+$vat);if($grand<0)$grand=0;
   $status=($_POST['submit_type']??'draft')==='approval'?'Pending Approval':'Draft';$submittedBy=$status==='Pending Approval'?($u['id']??0):null;$submittedAt=$status==='Pending Approval'?date('Y-m-d H:i:s'):null;
   $pdo=chb_db();$pdo->beginTransaction();$no=chb_next_voucher_no('sales_orders','order_no','SO');
   $st=$pdo->prepare('INSERT INTO sales_orders (order_no,order_date,customer_id,customer_name,customer_mobile,customer_address,previous_due,marketer_id,delivery_date,delivery_address,delivery_person,vehicle_no,payment_terms,subtotal,discount_amount,transport_amount,vat_amount,grand_total,remarks,status,submitted_by,submitted_at,created_by,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())');
   $st->execute([$no,$_POST['order_date']?:date('Y-m-d'),($_POST['customer_id']??0)?:null,$cust,trim($_POST['customer_mobile']??''),trim($_POST['customer_address']??''),so_n($_POST['previous_due']??0),($_POST['marketer_id']??0)?:null,($_POST['delivery_date']??'')?:null,trim($_POST['delivery_address']??''),trim($_POST['delivery_person']??''),trim($_POST['vehicle_no']??''),trim($_POST['payment_terms']??''),$sub,$discount,$transport,$vat,$grand,trim($_POST['remarks']??''),$status,$submittedBy,$submittedAt,$u['id']??0]);
   $oid=(int)$pdo->lastInsertId();$it=$pdo->prepare('INSERT INTO sales_order_items (sales_order_id,product_id,product_name,grade,bag_qty,kg_per_bag,total_kg,rate,line_total,sort_order,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,NOW())');foreach($items as $r){$it->execute([$oid,$r[0]?:null,$r[1],$r[2],$r[3],$r[4],$r[5],$r[6],$r[7],$r[8]]);}chb_audit('sales_orders','create',$oid,['order_no'=>$no,'status'=>$status,'grand_total'=>$grand]);$pdo->commit();chb_flash('success','Sales Order '.$no.' saved as '.$status.'.');header('Location: sales_orders.php');exit;
  }
  if($act==='approve'||$act==='reject'){$id=(int)($_POST['id']??0);if(!$id)throw new RuntimeException('Invalid order.');if(!chb_can('sales_orders.approve'))throw new RuntimeException('Approval permission denied.');$status=$act==='approve'?'Approved':'Rejected';$col=$act==='approve'?'approved':'rejected';$st=chb_db()->prepare("UPDATE sales_orders SET status=?, {$col}_by=?, {$col}_at=NOW(), approval_note=?, updated_by=?, updated_at=NOW() WHERE id=? AND deleted_at IS NULL");$st->execute([$status,$u['id']??0,trim($_POST['approval_note']??''),$u['id']??0,$id]);chb_audit('sales_orders',$act,$id,['status'=>$status]);chb_flash('success','Order '.$status.'.');header('Location: sales_orders.php');exit;}
 }catch(Throwable $e){if(isset($pdo)&&$pdo instanceof PDO&&$pdo->inTransaction())$pdo->rollBack();$errors[]=$e->getMessage();}
}
$orders=[];$nextNo='SO-'.date('Ymd').'-0001';if($ready){try{$nextNo=chb_next_voucher_no('sales_orders','order_no','SO');$w='deleted_at IS NULL';$p=[];$q=trim($_GET['q']??'');if($q!==''){$w.=' AND (order_no LIKE ? OR customer_name LIKE ? OR customer_mobile LIKE ?)';$p[]="%$q%";$p[]="%$q%";$p[]="%$q%";}if(($_GET['status']??'')!==''){$w.=' AND status=?';$p[]=$_GET['status'];}$st=chb_db()->prepare("SELECT * FROM sales_orders WHERE $w ORDER BY id DESC LIMIT 100");$st->execute($p);$orders=$st->fetchAll();}catch(Throwable $e){$errors[]=$e->getMessage();}}
ch_begin_app('order','Sales Orders');ch_wizard_steps(['Customer','Items','Delivery','Submit']);foreach($flash as$f)echo '<div class="alert alert-'.chb_e($f['type']).'">'.chb_e($f['message']).'</div>';foreach($errors as$er)echo '<div class="alert alert-danger">'.chb_e($er).'</div>';if(!$ready)echo '<div class="alert alert-warning"><strong>Backend table missing.</strong> Import <code>database/migrations/2026_07_07_sales_order_backend.sql</code> manually after DB backup.</div>';
?>
